SET NAMES utf8mb4;
SET CHARACTER SET utf8mb4;
USE quiz_pmrr;

-- Garante as categorias das duas legislações
SET @cat_estatuto := (SELECT id FROM categorias WHERE nome LIKE '%Estatuto dos Militares Estaduais de Roraima%' OR nome LIKE '%Estatuto dos Militares do Estado de Roraima%' ORDER BY id LIMIT 1);
SET @cat_codigo := (SELECT id FROM categorias WHERE nome = 'Código de Ética e Disciplina dos Militares do Estado de Roraima' ORDER BY id LIMIT 1);

