INSERT INTO categorias (nome, descricao) SELECT 'Código de Ética e Disciplina dos Militares do Estado de Roraima', 'Lei Ordinária nº 963, de 06 de fevereiro de 2014 - CEDM/RR' WHERE NOT EXISTS (SELECT 1 FROM categorias WHERE nome = 'Código de Ética e Disciplina dos Militares do Estado de Roraima');
INSERT INTO questoes (categoria_id, enunciado, opcao_a, opcao_b, opcao_c, opcao_d, resposta_correta, explicacao, referencia_legal, nivel) VALUES
(@cat_estatuto, 'Qual é o objeto principal da Lei Complementar nº 194/2012, Estatuto dos Militares do Estado de Roraima?', 'Regular apenas as punições disciplinares dos militares', 'Dispor sobre situação, obrigações, deveres, direitos, garantias, prerrogativas e atribuições dos militares estaduais', 'Criar exclusivamente o plano de carreira dos servidores civis', 'Regulamentar somente concursos públicos para oficiais', 'B', 'O Estatuto tem caráter amplo: disciplina a condição jurídica do militar estadual, tratando da situação funcional, direitos, deveres, garantias, prerrogativas e atribuições. A alternativa correta reproduz a finalidade central da LC nº 194/2012.', 'LC 194/2012, art. 1º', 'facil'),
(@cat_estatuto, 'Segundo o Estatuto, a Polícia Militar é organizada com base em quais princípios?', 'Legalidade e publicidade', 'Eficiência e moralidade administrativa', 'Hierarquia e disciplina militares', 'Antiguidade e merecimento exclusivamente', 'C', 'A Polícia Militar é instituição permanente, força auxiliar e reserva do Exército, organizada com base na hierarquia e disciplina militares, subordinada diretamente ao Governador do Estado.', 'LC 194/2012, art. 2º', 'facil'),
(@cat_estatuto, 'De acordo com o Estatuto, os militares estaduais podem encontrar-se em quais situações?', 'Ativos, licenciados e contratados', 'Na ativa ou na inatividade', 'Efetivos, temporários ou comissionados', 'Em exercício, cedidos ou afastados apenas', 'B', 'O art. 4º, §1º, divide a situação dos militares estaduais em duas grandes categorias: ativa e inatividade. A ativa inclui militares de carreira e reserva remunerada convocada; a inatividade inclui reserva remunerada e reformados.', 'LC 194/2012, art. 4º, §1º', 'facil'),
(@cat_estatuto, 'Quem são considerados militares estaduais de carreira?', 'Os nomeados para cargos civis temporários', 'Os que exercem serviço voluntário eventual', 'Os que desempenham voluntária e permanentemente o serviço militar, com estabilidade assegurada ou presumida', 'Todos os servidores públicos vinculados à segurança pública', 'C', 'O Estatuto define militares estaduais de carreira como aqueles que exercem voluntária e permanentemente o serviço militar e possuem estabilidade assegurada ou presumida.', 'LC 194/2012, art. 4º, §2º', 'medio'),
(@cat_estatuto, 'Qual alternativa apresenta corretamente uma etapa do concurso público prevista no Estatuto?', 'Somente entrevista com o comandante', 'Exames médicos, odontológicos, toxicológicos e de aptidão física, de caráter eliminatório', 'Apenas prova oral e sindicância social', 'Nomeação direta por antiguidade', 'B', 'O concurso público possui etapas, incluindo exames médicos, odontológicos, toxicológicos e de aptidão física. Esses exames têm caráter eliminatório, conforme a estrutura do art. 12.', 'LC 194/2012, art. 12', 'medio'),
(@cat_estatuto, 'A avaliação psicológica no concurso público tem qual caráter?', 'Classificatório e facultativo', 'Unicamente eliminatório', 'Apenas informativo', 'Classificatório para desempate', 'B', 'O Estatuto estabelece que a terceira etapa do concurso consta de avaliação psicológica, por exame psicotécnico, de caráter unicamente eliminatório.', 'LC 194/2012, art. 12, III', 'facil'),
(@cat_estatuto, 'Qual requisito de idade geral é previsto para ingresso na carreira militar estadual?', 'Mínima de 16 anos e máxima de 25 anos', 'Mínima de 18 anos e máxima de 35 anos, ressalvadas hipóteses específicas', 'Mínima de 21 anos e máxima de 40 anos para todos', 'Não há limite de idade', 'B', 'O Estatuto prevê idade mínima de 18 anos e máxima de 35 anos como regra geral, com ressalvas para quadros específicos, como saúde e capelão militar.', 'LC 194/2012, art. 17, IV', 'medio'),
(@cat_estatuto, 'Qual requisito de escolaridade é exigido, em regra, para o Quadro de Praças no ato da matrícula/posse?', 'Ensino fundamental incompleto', 'Ensino médio', 'Doutorado', 'Curso superior obrigatório para todos os praças', 'B', 'Para o Quadro de Praças, o Estatuto exige comprovação de conclusão do ensino médio, nos termos do art. 17, III, conforme redação atualizada.', 'LC 194/2012, art. 17, III', 'facil'),
(@cat_estatuto, 'O que acontece com o aluno que não obtiver aproveitamento intelectual, disciplinar ou frequência exigida nos cursos de formação?', 'Será promovido automaticamente', 'Será apenas advertido verbalmente', 'Será exonerado do curso de formação e excluído da respectiva instituição', 'Terá direito a repetir a prova infinitamente', 'C', 'O art. 18 prevê que o não aproveitamento intelectual, disciplinar ou a falta de frequência exigida leva à exoneração do curso de formação e exclusão da instituição.', 'LC 194/2012, art. 18', 'medio'),
(@cat_estatuto, 'Na hipótese de incapacidade temporária em razão de acidente em serviço durante curso de formação ou habilitação, comprovada por JIS, o Estatuto prevê:', 'Desligamento definitivo sem direito a retorno', 'Afastamento do curso e reingresso no próximo curso ofertado após cessar o impedimento', 'Promoção imediata por invalidez', 'Reclassificação obrigatória na mesma turma', 'B', 'O art. 18, §4º, garante o afastamento do curso e o reingresso no próximo curso ofertado pela instituição quando cessado o impedimento, sendo vedada a reclassificação.', 'LC 194/2012, art. 18, §4º', 'dificil'),
(@cat_estatuto, 'O curso de formação ou habilitação do militar estadual constitui:', 'Fase do estágio probatório', 'Apenas treinamento voluntário sem reflexo jurídico', 'Licença para capacitação civil', 'Período sem contagem para estabilidade', 'A', 'O art. 19 afirma expressamente que o curso de formação ou habilitação constitui uma fase do estágio probatório.', 'LC 194/2012, art. 19', 'facil'),
(@cat_estatuto, 'Quando a praça adquire estabilidade no serviço público militar estadual, segundo o Estatuto?', 'Ao completar 1 ano de serviço', 'Ao completar 3 anos de efetivo exercício e ser aprovada em avaliação de desempenho e conduta', 'No ato da inscrição no concurso', 'Somente ao ser promovida a oficial', 'B', 'A estabilidade é adquirida ao completar três anos de efetivo exercício, com aprovação em avaliação de desempenho técnico-profissional e conduta social civil ilibada.', 'LC 194/2012, art. 20', 'medio'),
(@cat_estatuto, 'Durante o estágio probatório, em quais períodos o militar estadual será avaliado?', 'Aos 6 e 12 meses', 'Aos 12 e 24 meses', 'Aos 18 e 30 meses', 'Apenas ao final do terceiro ano', 'C', 'O Estatuto estabelece duas avaliações no estágio probatório: a primeira aos 18 meses e a segunda aos 30 meses de exercício.', 'LC 194/2012, art. 21, §3º', 'dificil'),
(@cat_estatuto, 'Qual requisito de saúde aparece entre os requisitos de avaliação do estágio probatório?', 'Ser considerado apto pela Junta de Inspeção de Saúde/JIS', 'Apresentar atestado particular sem homologação', 'Ter apenas aptidão psicológica', 'Dispensa permanente de inspeção de saúde', 'A', 'O art. 21 inclui, entre os requisitos do estágio probatório, ser considerado apto pela Junta de Inspeção de Saúde/JIS.', 'LC 194/2012, art. 21, VIII', 'medio'),
(@cat_estatuto, 'Quais são os quadros de oficiais previstos no Estatuto?', 'QOC, QCO, QOS, QOM, QEO e QOCap', 'QPC, QPS, QEP e QPM', 'Apenas QOC e QEP', 'QSA, QAP e QOP', 'A', 'O art. 22, inciso I, relaciona os quadros de oficiais: Combatentes, Complementar, Saúde, Músicos, Especial de Oficiais e Capelães.', 'LC 194/2012, art. 22, I', 'medio'),
(@cat_estatuto, 'Quais são os quadros de praças previstos no Estatuto?', 'QOC, QCO e QEO', 'QPC, QPS, QEP e QPM', 'QOS, QOM e QOCap', 'Apenas QPC e QEP', 'B', 'O art. 22, II, prevê os quadros de praças: Combatentes, Saúde, Especial de Praças e Praças Músicos.', 'LC 194/2012, art. 22, II', 'facil'),
(@cat_estatuto, 'O Quadro Complementar de Oficiais da Polícia Militar é formado a partir de qual ingresso no CHO?', 'Entre soldados por sorteio', 'Entre subtenentes combatentes pelo critério de antiguidade', 'Entre civis indicados pelo Governador', 'Entre cabos por votação interna', 'B', 'O QCO tem acesso ao primeiro posto mediante mérito intelectual, conforme classificação final no CHO, cujo ingresso ocorre entre subtenentes combatentes pelo critério de antiguidade.', 'LC 194/2012, art. 22, §2º', 'dificil'),
(@cat_estatuto, 'Para o CHO de todos os quadros da Polícia Militar, o Estatuto prevê a obrigatoriedade de:', 'Exame de saúde, de caráter eliminatório', 'Teste de tiro anual apenas', 'Entrevista social classificatória', 'Curso superior dispensado em qualquer hipótese', 'A', 'O art. 22, §16, prevê que, para o CHO de todos os quadros da Polícia Militar, será obrigatória a realização do exame de saúde, de caráter eliminatório.', 'LC 194/2012, art. 22, §16', 'medio'),
(@cat_estatuto, 'O ingresso no CHO da Polícia Militar, de todos os quadros, dar-se-á entre os subtenentes por qual critério?', 'Sorteio público', 'Antiguidade', 'Indicação política', 'Maior idade', 'B', 'O art. 22, §17, dispõe que o ingresso no CHO da Polícia Militar, de todos os quadros, ocorre entre subtenentes pelo critério de antiguidade.', 'LC 194/2012, art. 22, §17', 'medio'),
(@cat_estatuto, 'Para matrícula no CHO da Polícia Militar, o Estatuto exige comprovação de:', 'Curso técnico em qualquer área', 'Curso superior reconhecido ou autorizado pelo Ministério da Educação', 'Ensino fundamental completo', 'Apenas experiência operacional', 'B', 'O art. 22, §17, exige, no ato da matrícula no CHO da Polícia Militar, a comprovação de curso superior reconhecido ou autorizado pelo Ministério da Educação.', 'LC 194/2012, art. 22, §17', 'medio'),
(@cat_estatuto, 'Segundo o Estatuto, hierarquia e disciplina são:', 'Faculdades administrativas opcionais', 'Princípios que constituem a base institucional das corporações', 'Regras aplicáveis apenas durante o serviço externo', 'Conceitos exclusivos dos oficiais', 'B', 'O art. 23 afirma que hierarquia e disciplina constituem a base institucional das corporações e devem ser mantidas em todas as circunstâncias da vida militar.', 'LC 194/2012, art. 23', 'facil'),
(@cat_estatuto, 'No Estatuto, a autoridade e a responsabilidade crescem com:', 'O tempo de folga', 'A elevação do grau hierárquico', 'A idade do militar, exclusivamente', 'A quantidade de cursos civis', 'B', 'O art. 23, §1º, estabelece que autoridade e responsabilidade aumentam conforme se eleva o grau hierárquico.', 'LC 194/2012, art. 23, §1º', 'facil'),
(@cat_estatuto, 'Como o Estatuto define disciplina?', 'Liberdade para cumprir ordens conforme conveniência', 'Rigorosa observância e acatamento integral das leis, regulamentos, normas e disposições', 'Apenas respeito aos superiores em solenidades', 'Ausência de punições registradas', 'B', 'A disciplina é definida como rigorosa observância e acatamento integral das normas que sustentam as instituições militares e coordenam seu funcionamento regular e harmônico.', 'LC 194/2012, art. 23, §4º', 'facil'),
(@cat_estatuto, 'A disciplina e o respeito à hierarquia devem ser mantidos:', 'Somente durante o expediente', 'Apenas em solenidades militares', 'Em todas as circunstâncias pelos militares em atividade ou na inatividade', 'Apenas por praças em serviço operacional', 'C', 'O Estatuto determina que disciplina e hierarquia sejam mantidas em todas as circunstâncias, tanto por militares em atividade quanto na inatividade.', 'LC 194/2012, art. 23, §5º', 'facil'),
(@cat_estatuto, 'Qual a finalidade dos círculos hierárquicos?', 'Separar definitivamente oficiais e praças sem convivência', 'Desenvolver camaradagem, estima e confiança, sem prejuízo do respeito mútuo', 'Eliminar a cadeia hierárquica', 'Definir exclusivamente remuneração', 'B', 'Os círculos hierárquicos são âmbitos de convivência destinados a desenvolver camaradagem, estima e confiança, preservando o respeito mútuo e a cadeia hierárquica.', 'LC 194/2012, art. 24', 'medio'),
(@cat_estatuto, 'O que é posto, segundo o Estatuto?', 'Grau hierárquico da Praça', 'Grau hierárquico do Oficial, conferido por ato do Governador e confirmado por Carta Patente', 'Função temporária de chefia', 'Cargo civil em comissão', 'B', 'Posto é o grau hierárquico do Oficial, conferido por ato do Governador do Estado e confirmado pela Carta Patente.', 'LC 194/2012, art. 25, §1º', 'facil'),
(@cat_estatuto, 'O que é graduação, segundo o Estatuto?', 'Grau hierárquico da Praça, conferido pelo Comandante-Geral', 'Grau hierárquico exclusivo dos oficiais', 'Documento de promoção por bravura', 'Curso de nível superior', 'A', 'Graduação é o grau hierárquico da Praça e é conferida pelo Comandante-Geral da Instituição.', 'LC 194/2012, art. 25, §2º', 'facil'),
(@cat_estatuto, 'A precedência hierárquica é regulada por:', 'Local de nascimento e idade dos dependentes', 'Posto ou graduação e antiguidade, salvo precedência funcional legal', 'Número de cursos civis e preferência pessoal', 'Apenas tempo de serviço total', 'B', 'O art. 26 regula a precedência pelo posto ou graduação e pela antiguidade no posto ou graduação, salvo precedência funcional prevista em lei.', 'LC 194/2012, art. 26', 'medio'),
(@cat_estatuto, 'Qual é o primeiro critério de antiguidade no posto ou graduação?', 'Data de nascimento', 'Data da promoção', 'Antiguidade dos quadros', 'Data de ingresso na corporação', 'B', 'A primeira regra de antiguidade é a data da promoção. Só depois se observam critérios sucessivos, como graus anteriores, ingresso, nascimento e antiguidade dos quadros.', 'LC 194/2012, art. 27, I', 'medio'),
(@cat_estatuto, 'Em igualdade de posto ou graduação, quem tem precedência?', 'Militares da inatividade sobre os da ativa', 'Militares da ativa sobre os da inatividade', 'O militar mais novo de idade', 'O que estiver em férias', 'B', 'O art. 27, §3º, dispõe que, em igualdade de posto ou graduação, os militares da ativa têm precedência sobre os da inatividade.', 'LC 194/2012, art. 27, §3º', 'medio'),
(@cat_estatuto, 'Qual alternativa está correta sobre os cadetes?', 'São hierarquicamente inferiores aos soldados', 'São hierarquicamente superiores aos subtenentes', 'Não possuem posição hierárquica', 'São equivalentes aos cabos', 'B', 'O Estatuto prevê expressamente que os cadetes são hierarquicamente superiores aos subtenentes.', 'LC 194/2012, art. 27, §7º', 'dificil'),
(@cat_estatuto, 'Cargo militar corresponde a:', 'Um conjunto de atribuições, deveres e responsabilidades que constituem as obrigações do titular', 'Apenas uma escala de serviço', 'Um benefício remuneratório', 'Uma função civil sem relação com a carreira', 'A', 'O cargo militar é especificado nos Quadros de Organização e corresponde ao conjunto de atribuições, deveres e responsabilidades do titular.', 'LC 194/2012, art. 29, §2º', 'facil'),
(@cat_estatuto, 'A vacância do cargo público militar pode decorrer de:', 'Promoção, reserva, reforma, falecimento, exoneração ou demissão, entre outras hipóteses', 'Apenas férias anuais', 'Somente mudança de endereço', 'Apenas transferência de setor', 'A', 'O art. 31 lista diversas hipóteses de vacância, incluindo exoneração, demissão, promoção, reserva, reforma, falecimento, perda do posto e patente, desertor e outras.', 'LC 194/2012, art. 31', 'medio'),
(@cat_estatuto, 'Função militar é definida como:', 'A atividade privada exercida pelo militar', 'O exercício das obrigações inerentes ao cargo militar', 'O cargo civil ocupado fora da corporação', 'O direito a férias anuais', 'B', 'A função militar é o exercício das obrigações inerentes ao cargo militar. A prova costuma diferenciar cargo, provimento e função.', 'LC 194/2012, art. 32', 'facil'),
(@cat_estatuto, 'Os cargos de Comandante e Subcomandante-Geral são privativos de qual quadro?', 'Quadro de Praças Combatentes', 'Quadro de Oficiais Combatentes', 'Quadro Especial de Praças', 'Quadro de Praças Músicos', 'B', 'O Estatuto prevê que os cargos de Comandante e Subcomandante-Geral da PM e CBM são privativos do Quadro de Oficiais Combatentes, pertencentes ao último posto.', 'LC 194/2012, art. 33', 'medio'),
(@cat_estatuto, 'Qual das alternativas é manifestação essencial do valor militar?', 'Amor à profissão militar e entusiasmo com que a exerce', 'Busca de facilidades pessoais pelo posto', 'Atividade comercial irrestrita', 'Manifestação coletiva reivindicatória', 'A', 'O art. 38 apresenta manifestações do valor militar, incluindo amor à profissão, entusiasmo, espírito de corpo, patriotismo, dedicação à sociedade e aprimoramento técnico-profissional.', 'LC 194/2012, art. 38', 'facil'),
(@cat_estatuto, 'Entre os preceitos da ética militar previstos no Estatuto está:', 'Ser indiscreto em linguagem escrita', 'Observar as normas de boa educação', 'Usar o posto para facilidades pessoais', 'Tratar assunto sigiloso fora do âmbito apropriado', 'B', 'O art. 39 lista preceitos da ética militar, entre eles observar as normas de boa educação, ser discreto e zelar pelo bom nome da instituição.', 'LC 194/2012, art. 39, XVIII', 'facil'),
(@cat_estatuto, 'Ao militar estadual da ativa, em regra, é vedado:', 'Participar como acionista ou quotista em sociedade permitida', 'Comerciar ou tomar parte na administração/gerência de sociedade, ressalvadas exceções legais', 'Estudar em curso autorizado', 'Receber instrução militar', 'B', 'O art. 40 veda ao militar da ativa comerciar ou tomar parte na administração/gerência de sociedade, excetuadas hipóteses legais como participação como acionista ou quotista.', 'LC 194/2012, art. 40', 'medio'),
(@cat_estatuto, 'Qual alternativa representa dever essencial dos militares estaduais?', 'Dedicação integral ao serviço e lealdade à instituição, mesmo com risco da própria vida', 'Prioridade absoluta a interesses particulares', 'Tratamento diferenciado sem urbanidade', 'Desprezo à hierarquia em folga', 'A', 'O art. 41 lista deveres essenciais, entre eles dedicação integral, lealdade institucional, probidade, moralidade, respeito à disciplina e hierarquia e tratamento digno a todos.', 'LC 194/2012, art. 41', 'facil'),
(@cat_estatuto, 'Segundo o Estatuto, o compromisso militar tem caráter:', 'Informal e opcional', 'Solene e prestado na presença da tropa', 'Secreto e verbal em particular', 'Exclusivamente escrito, sem solenidade', 'B', 'O compromisso militar é solene e prestado perante a tropa, quando o militar adquire conhecimento compatível com seus deveres.', 'LC 194/2012, art. 43', 'medio'),
(@cat_estatuto, 'Comando é definido pelo Estatuto como:', 'A soma de autoridade, deveres e responsabilidades de que o militar é investido quando conduz homens ou dirige OM', 'Apenas o direito de punir subordinados', 'Atividade administrativa sem responsabilidade', 'Função exercida somente por civis', 'A', 'O conceito de comando envolve autoridade, deveres e responsabilidades investidos legalmente ao militar que conduz homens ou dirige organização militar.', 'LC 194/2012, art. 44', 'facil'),
(@cat_estatuto, 'Aos alunos dos órgãos de formação, habilitação e aperfeiçoamento cabe:', 'Rigorosa observância das prescrições dos regulamentos e inteira dedicação ao estudo e aprendizado técnico-profissional', 'Livre dispensa das regras disciplinares', 'Atuar apenas em atividades civis', 'Escolher quais normas cumprir', 'A', 'O art. 48 exige dos alunos rigorosa observância dos regulamentos pertinentes e inteira dedicação ao estudo e aprendizado técnico-profissional.', 'LC 194/2012, art. 48', 'medio'),
(@cat_estatuto, 'A violação das obrigações ou deveres militares poderá constituir:', 'Apenas advertência verbal', 'Crime, contravenção penal ou transgressão disciplinar', 'Somente falta civil', 'Apenas irregularidade sem consequência', 'B', 'O Estatuto estabelece que a violação das obrigações ou deveres militares pode configurar crime, contravenção penal ou transgressão disciplinar, conforme a legislação.', 'LC 194/2012, art. 49', 'facil'),
(@cat_estatuto, 'A violação dos preceitos da ética, obrigações e deveres militares é mais grave quando:', 'Cometida por militar de grau hierárquico mais elevado', 'Cometida fora do horário administrativo', 'Praticada por militar mais antigo de idade apenas', 'Não houver testemunhas', 'A', 'O Estatuto reforça que a violação é mais grave quanto mais elevado for o grau hierárquico de quem a cometer.', 'LC 194/2012, art. 49, parágrafo único', 'medio'),
(@cat_estatuto, 'O militar submetido a processo administrativo disciplinar por suposta incompatibilidade ou incapacidade pode ser afastado cautelarmente por até:', '10 dias, sem prorrogação', '30 dias, prorrogáveis indefinidamente', '60 dias, prorrogáveis uma única vez por igual período', '180 dias automáticos', 'C', 'O art. 51 prevê afastamento cautelar por até 60 dias, prorrogável uma única vez por igual período, assegurados contraditório e ampla defesa.', 'LC 194/2012, art. 51', 'dificil'),
(@cat_estatuto, 'São proibidas pelo Estatuto manifestações coletivas de militares estaduais:', 'Tanto sobre atos superiores quanto de caráter reivindicatório ou político', 'Apenas durante formaturas', 'Somente quando houver uso de uniforme', 'Apenas em ambiente virtual', 'A', 'O art. 52 proíbe manifestações coletivas sobre atos superiores e manifestações de caráter reivindicatório ou político.', 'LC 194/2012, art. 52', 'medio'),
(@cat_estatuto, 'Qual lei define, especifica e classifica as transgressões disciplinares segundo o Estatuto?', 'A Lei de Licitações', 'O Código de Ética e Disciplina dos Militares do Estado de Roraima', 'O Código Eleitoral exclusivamente', 'A Lei Orgânica Municipal', 'B', 'O art. 54 afirma que o CEDM/RR define, especifica e classifica as transgressões disciplinares e disciplina punições, recursos, comportamento e recompensas.', 'LC 194/2012, art. 54', 'facil'),
(@cat_estatuto, 'A sanção disciplinar, segundo o Estatuto, não poderá ultrapassar:', '10 dias', '20 dias', '30 dias', '60 dias', 'C', 'O art. 54, §2º, estabelece que a sanção disciplinar não poderá ultrapassar o período de 30 dias.', 'LC 194/2012, art. 54, §2º', 'facil'),
(@cat_estatuto, 'O Conselho de Justificação destina-se a julgar:', 'A capacidade do oficial de permanecer ou não na ativa', 'A frequência de alunos em cursos civis', 'A escala de serviço voluntário', 'O direito de férias dos praças', 'A', 'O Conselho de Justificação é destinado ao julgamento da capacidade do oficial de permanecer ou não na ativa, conforme legislação específica.', 'LC 194/2012, art. 55', 'medio'),
(@cat_estatuto, 'O Conselho de Disciplina destina-se a julgar a capacidade de permanecer ou não na ativa de:', 'Apenas coronéis', 'Aspirante-a-Oficial e praça com estabilidade assegurada', 'Somente servidores civis', 'Candidatos ainda não nomeados', 'B', 'O art. 57 prevê Conselho de Disciplina para julgar a capacidade de permanecer ou não na ativa do Aspirante-a-Oficial e da praça com estabilidade assegurada.', 'LC 194/2012, art. 57', 'medio'),
(@cat_estatuto, 'Qual alternativa é direito dos militares estaduais previsto no Estatuto?', 'A promoção, nas condições legais', 'Comerciar livremente em serviço ativo', 'Descumprir ordem legal', 'Manifestar-se coletivamente sobre atos superiores', 'A', 'O art. 59 prevê diversos direitos, incluindo promoção, estabilidade, férias, uso das designações hierárquicas e outros, observadas as limitações legais.', 'LC 194/2012, art. 59', 'facil'),
(@cat_estatuto, 'A militar gestante ou em licença-maternidade não poderá ter direito suprimido em razão dessa condição, inclusive quanto a:', 'Vaga em curso de formação ou habilitação quando aprovada em processo seletivo interno', 'Perda automática de vaga em curso', 'Vedação permanente ao serviço administrativo', 'Exclusão do quadro de acesso sem análise', 'A', 'O Estatuto protege a militar gestante ou em licença-maternidade, inclusive quanto à vaga em curso de formação ou habilitação quando aprovada em processo seletivo interno.', 'LC 194/2012, art. 59, §§1º e 2º', 'medio'),
(@cat_estatuto, 'A jornada regular do militar estadual caracteriza-se por:', 'Atividades eventuais e facultativas', 'Atividades contínuas e inteiramente devotadas às finalidades da instituição militar', 'Trabalho exclusivamente remoto', 'Atividades civis sem vinculação militar', 'B', 'O art. 60-A define a jornada regular como atividades contínuas e inteiramente devotadas às finalidades da instituição militar, abrangendo serviço operacional e administrativo.', 'LC 194/2012, art. 60-A', 'medio'),
(@cat_estatuto, 'No serviço operacional de rádio patrulhamento da Polícia Militar, a proporção mínima prevista é:', 'Uma hora trabalhada para uma hora de folga', 'Uma hora trabalhada para duas horas de folga', 'Uma hora trabalhada para quatro horas de folga', 'Quatro horas trabalhadas para uma hora de folga', 'C', 'O art. 60-A, I, prevê, para rádio patrulhamento, escala com carga horária na proporção mínima de uma hora trabalhada para quatro horas de folga.', 'LC 194/2012, art. 60-A, I', 'dificil'),
(@cat_estatuto, 'Nas demais escalas de serviço operacional, a proporção mínima será:', 'Uma hora trabalhada para três horas de folga', 'Uma hora trabalhada para uma hora de folga sempre', 'Duas horas trabalhadas para uma hora de folga', 'Sem previsão legal', 'A', 'O art. 60-A, II, dispõe que, nas demais escalas de serviço operacional, a proporção mínima será de uma hora trabalhada para três horas de folga.', 'LC 194/2012, art. 60-A, II', 'dificil'),
(@cat_estatuto, 'O militar que atender ocorrência, mesmo não estando de serviço, será considerado:', 'Fora de serviço para todos os efeitos', 'Como se em serviço estivesse', 'Em atividade privada', 'Em licença compulsória', 'B', 'O art. 61 prevê que o militar estadual que atender ocorrência, mesmo não estando de serviço, será considerado para todos os efeitos legais como se em serviço estivesse.', 'LC 194/2012, art. 61', 'medio'),
(@cat_estatuto, 'A remuneração do militar estadual da ativa, segundo o Estatuto, é feita por:', 'Subsídio fixado em parcela única, com irredutibilidade', 'Comissão variável sem garantia', 'Diárias permanentes', 'Pagamento por produtividade somente', 'A', 'O art. 63 estabelece remuneração por subsídio fixado em parcela única, garantindo a irredutibilidade, observadas as regras constitucionais e legais.', 'LC 194/2012, art. 63', 'medio'),
(@cat_estatuto, 'A remuneração do militar não será objeto de arresto, sequestro ou penhora, exceto em caso de:', 'Prestação de alimentos resultante de decisão judicial', 'Dívida comercial comum sem decisão', 'Multa disciplinar verbal', 'Compra particular parcelada', 'A', 'O art. 65 protege a remuneração do militar contra arresto, sequestro ou penhora, salvo nos casos de prestação de alimentos por decisão judicial.', 'LC 194/2012, art. 65', 'dificil'),
(@cat_estatuto, 'A promoção é um ato administrativo que visa:', 'Preencher seletivamente claros existentes nos postos e graduações superiores', 'Conceder férias automáticas', 'Transferir militar para atividade civil', 'Substituir o estágio probatório', 'A', 'A promoção visa ao preenchimento seletivo dos claros nos postos e graduações superiores, obedecendo datas e legislação específica.', 'LC 194/2012, art. 71', 'facil'),
(@cat_estatuto, 'As datas de promoções da Polícia Militar são, em regra:', '21 de abril, 21 de agosto e 25 de dezembro', '1º de janeiro, 7 de setembro e 15 de novembro', '22 de março, 2 de julho e 19 de dezembro', '10 de junho e 15 de agosto', 'A', 'O art. 71, §2º, fixa as datas de promoção da Polícia Militar em 21 de abril, 21 de agosto e 25 de dezembro.', 'LC 194/2012, art. 71, §2º', 'dificil'),
(@cat_estatuto, 'O Subtenente QEP, para fazer jus à matrícula no CHO conforme art. 71-A, §6º atualizado, deve completar:', '15 anos de tempo de serviço e comportamento bom', '19 anos de tempo de serviço, comportamento no mínimo ótimo, observado critério de antiguidade e disponibilidade de vagas', '25 anos de contribuição e comportamento insuficiente', '10 anos de serviço e curso técnico', 'B', 'A redação atualizada do art. 71-A, §6º, prevê 19 anos de tempo de serviço, comportamento no mínimo ótimo, critério de antiguidade e disponibilidade de vagas para matrícula no CHO.', 'LC 194/2012, art. 71-A, §6º', 'dificil'),
(@cat_estatuto, 'As promoções serão realizadas por quais critérios, entre outros previstos no art. 73?', 'Antiguidade, merecimento, ato de bravura, post-mortem, tempo de contribuição, mérito intelectual e ressarcimento de preterição', 'Apenas por indicação política', 'Somente por idade', 'Apenas por sorteio', 'A', 'O art. 73 prevê múltiplos critérios de promoção, como antiguidade, merecimento, bravura, post-mortem, tempo de contribuição, tempo de efetivo serviço, mérito intelectual e ressarcimento de preterição.', 'LC 194/2012, art. 73', 'medio'),
(@cat_estatuto, 'A promoção por ato de bravura é:', 'Forma excepcional, resultante de ato incomum de coragem, audácia e abnegação', 'Forma automática por tempo de serviço', 'Exclusiva para quem conclui curso superior', 'Obrigatória a cada ano', 'A', 'O art. 73 define ato de bravura como forma excepcional de promoção decorrente de atos incomuns de coragem, audácia e abnegação, úteis às operações militares e avaliados por comissão.', 'LC 194/2012, art. 73, III', 'medio'),
(@cat_codigo, 'Qual é a finalidade do Código de Ética e Disciplina dos Militares de Roraima?', 'Apenas regulamentar férias', 'Definir, especificar e classificar transgressões disciplinares e estabelecer normas sobre punições, comportamento, valores, ética, recursos e recompensas', 'Criar cargos civis temporários', 'Tratar somente de remuneração', 'B', 'O art. 1º do CEDM/RR descreve sua finalidade: disciplinar transgressões, punições, comportamento, valores, preceitos éticos, recursos e recompensas.', 'Lei 963/2014, art. 1º', 'facil'),
(@cat_codigo, 'A quem se aplica o Código de Ética e Disciplina?', 'Somente aos militares ativos', 'Aos militares ativos e inativos, alunos de formação/especialização/aperfeiçoamento e militares cedidos nas hipóteses legais', 'Apenas aos oficiais combatentes', 'Somente a servidores civis da segurança pública', 'B', 'O art. 2º prevê aplicação aos militares ativos e inativos, alunos de órgãos de ensino militar e militares oriundos do ex-Território cedidos ao Estado, nas hipóteses legais.', 'Lei 963/2014, art. 2º', 'facil'),
(@cat_codigo, 'Segundo o CEDM/RR, hierarquia militar é:', 'A ordenação progressiva da autoridade em níveis diferentes, decorrente da obediência dentro das estruturas militares', 'Apenas a idade dos militares', 'A relação entre civis e militares', 'O direito de escolher ordens convenientes', 'A', 'O art. 5º define hierarquia como ordenação progressiva da autoridade, em níveis diferentes, nas estruturas da PM e CBM, com grau máximo no Governador.', 'Lei 963/2014, art. 5º', 'facil'),
(@cat_codigo, 'No CEDM/RR, disciplina militar é:', 'A ausência de punições', 'A rigorosa observância e acatamento integral das leis, regulamentos, normas e disposições', 'A obediência apenas a ordens escritas', 'O cumprimento seletivo de normas', 'B', 'O art. 8º define disciplina como rigorosa observância e acatamento integral das normas, traduzindo-se pelo perfeito cumprimento do dever.', 'Lei 963/2014, art. 8º', 'facil'),
(@cat_codigo, 'Qual é uma manifestação essencial de disciplina prevista no Código?', 'Desobediência funcional', 'Colaboração espontânea à disciplina coletiva e à eficiência das instituições', 'Uso da função para interesse particular', 'Comentário depreciativo de companheiros', 'B', 'O art. 8º, §1º, elenca manifestações essenciais da disciplina, incluindo correção de atitudes, obediência pronta, dedicação integral e colaboração espontânea.', 'Lei 963/2014, art. 8º, §1º', 'facil'),
(@cat_codigo, 'Sobre obediência às ordens, qual alternativa está correta?', 'As ordens devem ser prontamente obedecidas, desde que não manifestamente ilegais', 'Toda ordem ilegal deve ser cumprida sem questionamento', 'Ordens verbais nunca têm validade', 'O subordinado jamais responde por excessos', 'A', 'O art. 9º estabelece a regra central: ordens devem ser prontamente obedecidas, desde que não sejam manifestamente ilegais. Não há obediência cega à ilegalidade evidente.', 'Lei 963/2014, art. 9º', 'facil'),
(@cat_codigo, 'Cabe ao subordinado, ao receber uma ordem:', 'Ignorá-la se tiver dúvida', 'Solicitar esclarecimentos necessários ao total entendimento e compreensão', 'Cumpri-la com excesso para demonstrar zelo', 'Registrar que não tem responsabilidade', 'B', 'O art. 9º, §2º, prevê que o subordinado deve solicitar esclarecimentos necessários ao completo entendimento da ordem.', 'Lei 963/2014, art. 9º, §2º', 'medio'),
(@cat_codigo, 'Quem responde pelos excessos e abusos no cumprimento de ordem recebida?', 'Somente o superior que deu a ordem', 'O militar estadual que exorbitar ou se omitir no cumprimento da ordem', 'Ninguém, se havia ordem superior', 'Apenas a instituição', 'B', 'O art. 9º, §3º, atribui responsabilidade ao militar que exorbitar ou se omitir no cumprimento da ordem, pelos excessos, abusos ou omissões.', 'Lei 963/2014, art. 9º, §3º', 'medio'),
(@cat_codigo, 'Comando, segundo o CEDM/RR, é:', 'Soma de autoridade, deveres e responsabilidades investida legalmente quando o militar conduz homens ou dirige OM', 'Apenas antiguidade no posto', 'Uma punição disciplinar', 'Um direito exclusivo de praças', 'A', 'O art. 10 define comando como soma de autoridade, deveres e responsabilidades quando o militar conduz homens ou dirige organização militar.', 'Lei 963/2014, art. 10', 'facil'),
(@cat_codigo, 'A subordinação, conforme o Código:', 'Afeta a dignidade pessoal do militar', 'Não afeta a dignidade pessoal e decorre das estruturas hierarquizadas', 'Só existe entre oficiais', 'Dispensa respeito mútuo', 'B', 'O art. 11 afirma que a subordinação não afeta a dignidade pessoal do militar e decorre exclusivamente das estruturas hierarquizadas.', 'Lei 963/2014, art. 11', 'facil'),
(@cat_codigo, 'Os oficiais são preparados ao longo da carreira para:', 'Exercer apenas atividades administrativas civis', 'Exercício do comando, chefia e direção das Organizações Militares', 'Substituir todas as praças em serviço', 'Atuar sem responsabilidade funcional', 'B', 'O art. 12 dispõe que os oficiais são preparados para comando, chefia e direção das organizações militares.', 'Lei 963/2014, art. 12', 'facil'),
(@cat_codigo, 'Subtenentes e Sargentos devem impor-se, entre outros aspectos, por:', 'Lealdade, exemplo e capacidade profissional e técnica', 'Apenas antiguidade cronológica', 'Imposição sem respeito', 'Interesse particular', 'A', 'O art. 13, parágrafo único, prevê que Subtenentes e Sargentos devem impor-se pela lealdade, exemplo e capacidade profissional e técnica.', 'Lei 963/2014, art. 13', 'medio'),
(@cat_codigo, 'Cabos e Soldados devem ser empregados prioritariamente:', 'Na execução das atividades operacionais', 'Na direção exclusiva de OM', 'Em cargos civis de gerência', 'Em atividades comerciais', 'A', 'O art. 14 prevê emprego prioritário de Cabos e Soldados na execução das atividades operacionais.', 'Lei 963/2014, art. 14', 'facil'),
(@cat_codigo, 'Deontologia Militar é constituída por:', 'Valores e deveres éticos traduzidos em normas de conduta', 'Apenas regras de armamento', 'Normas de trânsito civil', 'Benefícios remuneratórios', 'A', 'O art. 15 define deontologia militar como conjunto de valores e deveres éticos traduzidos em normas de conduta voltadas ao bem comum e à preservação da ordem pública.', 'Lei 963/2014, art. 15', 'medio'),
(@cat_codigo, 'A camaradagem é considerada:', 'Dispensável no convívio militar', 'Indispensável ao convívio dos militares, preservando boas relações sociais', 'Vedada entre militares de círculos diferentes', 'Exclusiva de militares da inatividade', 'B', 'O art. 16 afirma que a camaradagem é indispensável ao convívio dos militares e deve preservar as melhores relações sociais.', 'Lei 963/2014, art. 16', 'facil'),
(@cat_codigo, 'A civilidade, no Código, é parte da:', 'Educação militar e de interesse vital para a disciplina consciente', 'Escala de serviço voluntário', 'Remuneração por subsídio', 'Promoção por merecimento', 'A', 'O art. 17 trata a civilidade como parte da educação militar e vital para a disciplina consciente, exigindo consideração, justiça, respeito e deferência.', 'Lei 963/2014, art. 17', 'medio'),
(@cat_codigo, 'Qual alternativa corresponde a valor militar previsto no art. 18?', 'Respeito à dignidade humana', 'Promoção pessoal por publicidade', 'Uso da função para negócios particulares', 'Desrespeito à hierarquia', 'A', 'O art. 18 lista vários valores, incluindo respeito à dignidade humana, justiça, solidariedade, lealdade, honra, honestidade, hierarquia, disciplina e coragem.', 'Lei 963/2014, art. 18', 'facil'),
(@cat_codigo, 'Sentimento do dever é:', 'Exercício das funções com autoridade e eficiência, cumprimento das leis, regulamentos e ordens e dedicação integral ao serviço', 'Apenas sensação subjetiva sem vínculo funcional', 'Preferência por serviços administrativos', 'Faculdade de não cumprir missão', 'A', 'O art. 19, §1º, define sentimento do dever como exercício eficiente das funções, cumprimento das normas e dedicação integral ao serviço.', 'Lei 963/2014, art. 19, §1º', 'medio'),
(@cat_codigo, 'Pundonor militar é:', 'Dever de pautar a conduta com correção de atitudes e comportamento ético', 'Direito de recusar toda ordem', 'Apenas antiguidade funcional', 'Benefício pecuniário', 'A', 'O art. 19, §3º, relaciona pundonor militar à conduta correta, digna e ética em qualquer ocasião.', 'Lei 963/2014, art. 19, §3º', 'medio'),
(@cat_codigo, 'Qual preceito ético está previsto no art. 20 do CEDM/RR?', 'Atuar com devotamento ao interesse público, colocando-o acima dos anseios particulares', 'Buscar publicidade para promoção pessoal', 'Aceitar vantagens em razão da função', 'Tratar cidadãos de forma descortês', 'A', 'O art. 20 elenca preceitos éticos e exige atuação voltada ao interesse público, acima de interesses particulares.', 'Lei 963/2014, art. 20, IV', 'facil'),
(@cat_codigo, 'O Código determina que o militar deve considerar quais fundamentos de dignidade pessoal?', 'Verdade, legalidade e responsabilidade', 'Apenas antiguidade e idade', 'Publicidade pessoal e vantagem', 'Silêncio, segredo e conveniência', 'A', 'O art. 20, XVIII, estabelece verdade, legalidade e responsabilidade como fundamentos de dignidade pessoal.', 'Lei 963/2014, art. 20, XVIII', 'medio'),
(@cat_codigo, 'No âmbito do ensino militar, o art. 20 veda:', 'Usar meio ilícito na produção de trabalho intelectual ou em avaliação profissional', 'Estudar em grupo', 'Fazer resumo próprio', 'Pedir esclarecimento ao professor', 'A', 'O art. 20, XXV, veda o uso de meio ilícito em trabalho intelectual ou avaliação profissional, inclusive no ensino militar.', 'Lei 963/2014, art. 20, XXV', 'facil'),
(@cat_codigo, 'O militar deve tratar subordinado e superior hierárquico:', 'Dignamente e com urbanidade', 'Com descaso se estiver de folga', 'Apenas por escrito', 'Sem formalidade alguma', 'A', 'O art. 20, XXXVIII, exige tratamento digno e urbano entre subordinados e superiores.', 'Lei 963/2014, art. 20, XXXVIII', 'facil'),
(@cat_codigo, 'Ao militar da ativa é vedado, em regra:', 'Exercer atividade de segurança particular e atividade comercial ou industrial, ressalvadas as permitidas pela legislação', 'Estudar legislação militar', 'Cumprir ordem legal', 'Atuar em missão operacional', 'A', 'O art. 21 veda ao militar da ativa exercer segurança particular e atividade comercial ou industrial, salvo permissões legais.', 'Lei 963/2014, art. 21', 'medio'),
(@cat_codigo, 'A violação dos deveres militares acarretará responsabilidade:', 'Apenas administrativa, excluindo penal e cível', 'Administrativa, independentemente da penal e da cível', 'Somente moral', 'Nenhuma se cometida por superior', 'B', 'O art. 24 prevê responsabilidade administrativa independentemente das responsabilidades penal e cível.', 'Lei 963/2014, art. 24', 'facil'),
(@cat_codigo, 'A competência para aplicar as prescrições do CEDM/RR é conferida:', 'À função exercida, observada a hierarquia', 'A qualquer cidadão', 'Somente ao militar mais antigo de idade', 'Ao subordinado direto', 'A', 'O art. 26 estabelece que a competência é conferida à função exercida, observada a hierarquia.', 'Lei 963/2014, art. 26', 'medio'),
(@cat_codigo, 'Quem é competente para aplicar todas as sanções disciplinares previstas no Código?', 'Governador do Estado', 'Comandante de Pelotão', 'Soldado mais antigo', 'Qualquer chefe civil', 'A', 'O art. 27 atribui ao Governador do Estado competência para aplicar todas as sanções disciplinares previstas no Código, após o devido processo legal.', 'Lei 963/2014, art. 27', 'medio'),
(@cat_codigo, 'Todo militar que tiver conhecimento de fato contrário à disciplina deve comunicá-lo em qual prazo?', '24 horas corridas', '5 dias úteis', '30 dias corridos', '90 dias', 'B', 'O art. 28 determina comunicação ao chefe imediato, por escrito, no prazo máximo de 5 dias úteis contados da observação ou conhecimento do fato.', 'Lei 963/2014, art. 28', 'dificil'),
(@cat_codigo, 'A Comunicação Disciplinar deve ser:', 'Clara, concisa e precisa, sem comentários ou opiniões pessoais', 'Anônima e sem data', 'Verbal e informal', 'Com opinião pessoal extensa obrigatória', 'A', 'O art. 28, §2º, exige comunicação clara, concisa, precisa, com dados do fato e sem comentários ou opiniões pessoais.', 'Lei 963/2014, art. 28, §2º', 'medio'),
(@cat_codigo, 'O acusado, após notificação formal da comunicação disciplinar, terá prazo de:', '2 dias corridos', '5 dias úteis para alegações de defesa por escrito', '15 dias para recurso judicial', '30 dias para representação', 'B', 'O art. 28, §4º, prevê prazo de 5 dias úteis para o acusado apresentar alegações de defesa por escrito a partir do recebimento.', 'Lei 963/2014, art. 28, §4º', 'dificil'),
(@cat_codigo, 'Queixa Disciplinar é:', 'Comunicação por escrito feita pelo subordinado atingido por ato pessoal de superior que repute irregular ou injusto', 'Recurso de civil contra militar', 'Pedido de férias', 'Denúncia anônima coletiva', 'A', 'O art. 29 define queixa disciplinar como comunicação escrita do subordinado atingido por ato pessoal de superior hierárquico considerado irregular ou injusto.', 'Lei 963/2014, art. 29', 'medio'),
(@cat_codigo, 'O prazo para apresentação da Queixa Disciplinar é de:', '5 dias úteis a contar da data do fato', '10 dias corridos após boletim', '30 dias após ciência', '1 ano', 'A', 'O art. 29, §1º, prevê prazo máximo de 5 dias úteis para apresentação da queixa, contado da data do fato.', 'Lei 963/2014, art. 29, §1º', 'dificil'),
(@cat_codigo, 'Representação, no CEDM/RR, é usada quando o militar:', 'Considera-se vítima de abuso por autoridade funcionalmente superior que atente contra direito legalmente garantido', 'Quer trocar férias', 'Deseja alterar escala sem motivo', 'Pretende pedir promoção automática', 'A', 'O art. 30 define representação como instrumento do militar que se considera vítima de abuso por autoridade superior contra direito legalmente garantido.', 'Lei 963/2014, art. 30', 'medio'),
(@cat_codigo, 'O prazo para interposição de Representação é de:', '5 dias úteis', '10 dias úteis', '30 dias a contar do conhecimento do fato abusivo', '180 dias', 'C', 'O art. 31, parágrafo único, fixa prazo de 30 dias a contar do conhecimento do fato considerado abusivo, devendo ser apreciada em igual período.', 'Lei 963/2014, art. 31', 'dificil'),
(@cat_codigo, 'Transgressão disciplinar é:', 'Qualquer violação aos princípios da ética, deveres e obrigações militares, ou ação/omissão contrária a leis, regulamentos e normas', 'Somente crime militar', 'Apenas erro sem consequência', 'Somente falta cometida em serviço armado', 'A', 'O art. 33 define transgressão disciplinar de forma ampla, abrangendo violações éticas, deveres, obrigações e ações ou omissões contrárias às normas.', 'Lei 963/2014, art. 33', 'facil'),
(@cat_codigo, 'As transgressões disciplinares classificam-se em:', 'Leve, média ou grave', 'Administrativa e judicial apenas', 'Simples e complexa', 'Escrita e verbal', 'A', 'O art. 34 classifica as transgressões de acordo com a gravidade em leve, média ou grave.', 'Lei 963/2014, art. 34', 'facil'),
(@cat_codigo, 'Segundo o art. 34, é de natureza grave a transgressão que:', 'Seja atentatória aos direitos humanos fundamentais', 'Cause pequeno transtorno sem prejuízo', 'Consista apenas em atraso justificado', 'Não tenha relação com serviço militar', 'A', 'O art. 34 considera grave, entre outras hipóteses, o ato atentatório aos direitos humanos fundamentais, às instituições ou ao Estado, ou que afete honra, decoro e dever.', 'Lei 963/2014, art. 34, II', 'medio'),
(@cat_codigo, 'No julgamento das transgressões, deve-se considerar:', 'Antecedentes, causas, natureza dos fatos e consequências', 'Apenas a opinião do superior', 'Somente o posto do acusado', 'Apenas o resultado financeiro', 'A', 'O art. 35 exige análise dos antecedentes, causas, natureza dos fatos/atos e consequências que possam advir.', 'Lei 963/2014, art. 35', 'medio'),
(@cat_codigo, 'É causa de justificação:', 'Obediência a ordem superior, quando não manifestamente ilegal', 'Mau comportamento', 'Reincidência específica', 'Prática em presença de público', 'A', 'O art. 37 lista causas de justificação, incluindo obediência à ordem superior quando não manifestamente ilegal. Reconhecida a causa, não haverá transgressão disciplinar.', 'Lei 963/2014, art. 37, III', 'facil'),
(@cat_codigo, 'Qual alternativa é circunstância atenuante?', 'Bom comportamento', 'Mau comportamento', 'Reincidência específica', 'Conluio de duas ou mais pessoas', 'A', 'O art. 38 lista circunstâncias atenuantes, incluindo bom comportamento, serviços relevantes, confissão espontânea e tentativa de diminuir consequências.', 'Lei 963/2014, art. 38', 'facil'),
(@cat_codigo, 'Qual alternativa é circunstância agravante?', 'Confissão espontânea', 'Bom comportamento', 'Prática da transgressão em presença de público', 'Ter evitado mal maior', 'C', 'O art. 39 considera agravante, entre outras, a prática da transgressão em presença de público, de tropa, de subordinado ou durante serviço.', 'Lei 963/2014, art. 39', 'medio'),
(@cat_codigo, 'Para o Código, reincidência específica considera o mesmo item do art. 40 em qual intervalo?', '6 meses', '1 ano', '3 anos', '5 anos', 'C', 'O art. 39, §1º, define reincidência específica como enquadramento no mesmo item do art. 40 no intervalo de 3 anos.', 'Lei 963/2014, art. 39, §1º', 'dificil'),
(@cat_codigo, 'Chegar atrasado ao expediente ou serviço sem justificativa é transgressão de natureza:', 'Leve', 'Média', 'Grave', 'Não é transgressão', 'A', 'O art. 40, §1º, II, classifica como transgressão leve chegar atrasado ao expediente, serviço ou ato em que deva tomar parte, sem justificativa.', 'Lei 963/2014, art. 40, §1º, II', 'facil'),
(@cat_codigo, 'Faltar ao expediente ou ao serviço para o qual esteja escalado é transgressão de natureza:', 'Leve', 'Média', 'Grave', 'Apenas administrativa civil', 'C', 'O art. 40, §3º, XVII, classifica como grave faltar ao expediente ou serviço para o qual esteja escalado.', 'Lei 963/2014, art. 40, §3º, XVII', 'facil'),
(@cat_codigo, 'Dormir em serviço, salvo quando autorizado, é transgressão:', 'Leve', 'Média', 'Grave', 'Sem previsão no Código', 'C', 'O art. 40, §3º, XIII, tipifica como transgressão grave dormir em serviço, salvo quando autorizado.', 'Lei 963/2014, art. 40, §3º, XIII', 'facil'),
(@cat_codigo, 'As punições disciplinares são apresentadas em ordem crescente de gravidade. Qual é a mais branda?', 'Advertência', 'Detenção disciplinar', 'Demissão', 'Exclusão a bem da disciplina', 'A', 'O art. 42 apresenta as punições em ordem crescente de gravidade, iniciando pela advertência.', 'Lei 963/2014, art. 42', 'facil'),
(@cat_codigo, 'A advertência aplica-se exclusivamente a faltas de natureza:', 'Leve', 'Média', 'Grave', 'Crime militar', 'A', 'O art. 43, §2º, dispõe que a advertência aplica-se exclusivamente às faltas de natureza leve e não altera o comportamento do militar.', 'Lei 963/2014, art. 43, §§2º e 3º', 'facil'),
(@cat_codigo, 'A repreensão é punição:', 'Verbal e sem registro', 'Feita por escrito, publicada em Boletim Geral e não priva o punido da liberdade', 'Cumprida com confinamento absoluto', 'Aplicável apenas a faltas graves', 'B', 'O art. 44 define repreensão como punição escrita e publicada em Boletim Geral, sem privação de liberdade, aplicável a faltas leves e médias.', 'Lei 963/2014, art. 44', 'medio'),
(@cat_codigo, 'A Permanência Disciplinar consiste em:', 'Cerceamento da liberdade, permanecendo o punido nas dependências militares sem ficar confinado', 'Retenção sem participar de qualquer atividade', 'Demissão automática', 'Advertência verbal', 'A', 'O art. 45 define permanência disciplinar como cerceamento da liberdade, com permanência nas dependências da unidade, sem confinamento.', 'Lei 963/2014, art. 45', 'medio'),
(@cat_codigo, 'A Detenção Disciplinar somente poderá ser aplicada no cometimento de transgressão de natureza:', 'Leve', 'Média', 'Grave', 'Qualquer natureza, inclusive sem processo', 'C', 'O art. 46, §2º, prevê que a Detenção Disciplinar somente poderá ser aplicada em transgressão disciplinar de natureza grave.', 'Lei 963/2014, art. 46, §2º', 'facil'),
(@cat_codigo, 'As punições de Permanência Disciplinar ou Detenção Disciplinar não podem ultrapassar:', '10 dias', '15 dias', '30 dias', '60 dias', 'C', 'O art. 50 estabelece limite máximo de 30 dias para punições disciplinares de Permanência ou Detenção Disciplinar.', 'Lei 963/2014, art. 50', 'facil'),
(@cat_codigo, 'Na aplicação da punição, devem constar, entre outros elementos:', 'Descrição sumária, clara e precisa dos fatos, enquadramento e publicação em Boletim Geral', 'Apenas o nome do acusado', 'Somente a opinião da autoridade', 'Apenas o resultado da escala', 'A', 'O art. 51 exige descrição sumária, clara e precisa dos fatos e circunstâncias, enquadramento da punição e publicação em Boletim Geral.', 'Lei 963/2014, art. 51', 'medio'),
(@cat_codigo, 'Por uma única transgressão:', 'Devem ser aplicadas duas punições obrigatoriamente', 'Não deve ser aplicada mais de uma punição', 'Sempre cabe detenção e permanência simultâneas', 'Não pode haver responsabilidade civil ou penal', 'B', 'O art. 53, §4º, determina que por uma única transgressão não deve ser aplicada mais de uma punição; isso não exclui responsabilidade civil ou penal.', 'Lei 963/2014, art. 53, §§4º e 5º', 'medio'),
(@cat_codigo, 'Nenhum militar deverá ser interrogado quando estiver:', 'Em estado de embriaguez ou sob ação de alucinógenos ou entorpecentes', 'Uniformizado', 'Na presença de advogado', 'Em expediente administrativo', 'A', 'O art. 54 veda interrogatório de militar em estado de embriaguez ou sob ação de alucinógenos ou entorpecentes.', 'Lei 963/2014, art. 54', 'facil'),
(@cat_codigo, 'O Recolhimento Disciplinar Cautelar não excederá o prazo de:', '24 horas', '3 dias', '10 dias', '30 dias', 'B', 'O art. 61, §3º, estabelece que o Recolhimento Disciplinar Cautelar não excederá o prazo de 3 dias, computados da efetivação.', 'Lei 963/2014, art. 61, §3º', 'dificil'),
(@cat_codigo, 'Qual direito é garantido ao militar recolhido cautelarmente?', 'Saber por escrito o motivo da medida', 'Ficar incomunicável obrigatoriamente', 'Não receber alimentação', 'Não comunicar família ou advogado', 'A', 'O art. 63 garante direitos ao recolhido cautelarmente, como saber o motivo por escrito, identificar o responsável, comunicar família/advogado e receber alimentação, alojamento e assistência médica.', 'Lei 963/2014, art. 63', 'medio');